def evaluate_threshold(retriever, test_cases, threshold):
    retriever.threshold = threshold
    tp = fp = fn = 0
    for query, relevant_idx in test_cases:
        results = retriever.retrieve(query)
        retrieved = {r["text"] for r in results}
        expected = {retriever.texts[i] for i in relevant_idx}
        tp += len(retrieved & expected)
        fp += len(retrieved - expected)
        fn += len(expected - retrieved)
    prec = tp / (tp + fp) if (tp + fp) else 0
    rec = tp / (tp + fn) if (tp + fn) else 0
    f1 = 2 * prec * rec / (prec + rec) if (prec + rec) else 0
    return {"t": threshold, "P": prec, "R": rec, "F1": f1}

# Ground truth: (query, relevant_indices)
cases = [
    ("Python list creation", [0]),
    ("database queries", [1]),
    ("unrelated topic", []),
]

for t in [0.2, 0.3, 0.4, 0.5]:
    r = evaluate_threshold(retriever, cases, t)
    print(f"t={r['t']:.1f} P={r['P']:.2f} R={r['R']:.2f} F1={r['F1']:.2f}")
